import{_ as t,o as a,c as r,a2 as n}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"Capy — Benchmarks","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/capy/benchmarks.md","filePath":"research/agents/capy/benchmarks.md"}'),o={name:"research/agents/capy/benchmarks.md"};function s(i,e,l,d,h,c){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="capy-—-benchmarks" tabindex="-1">Capy — Benchmarks <a class="header-anchor" href="#capy-—-benchmarks" aria-label="Permalink to &quot;Capy — Benchmarks&quot;">​</a></h1><blockquote><p>Terminal-Bench 2.0 results: rank #7 with Claude Opus 4.6 at 75.3% ±2.4.</p></blockquote><h2 id="terminal-bench-2-0" tabindex="-1">Terminal-Bench 2.0 <a class="header-anchor" href="#terminal-bench-2-0" aria-label="Permalink to &quot;Terminal-Bench 2.0&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Agent + Model</th><th>Rank</th><th>Score</th><th>Date</th></tr></thead><tbody><tr><td>Capy + Claude Opus 4.6</td><td>#7</td><td>75.3% ±2.4</td><td>2026-03-12</td></tr></tbody></table><h3 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h3><p><strong>Terminal-Bench 2.0</strong> is a benchmark for evaluating AI coding agents on real-world terminal-based software engineering tasks. A rank of #7 places Capy in the upper tier of commercial coding agents.</p><p>For reference, nearby results on the same benchmark (as of the same period):</p><table tabindex="0"><thead><tr><th>Rank</th><th>Agent</th><th>Score</th></tr></thead><tbody><tr><td>#1</td><td>ForgeCode (Claude Opus 4.6 / GPT-5.4)</td><td>81.8%</td></tr><tr><td>#6</td><td>Droid + GPT-5.3-Codex</td><td>77.3%</td></tr><tr><td><strong>#7</strong></td><td><strong>Capy + Claude Opus 4.6</strong></td><td><strong>75.3% ±2.4</strong></td></tr></tbody></table><h3 id="interpretation" tabindex="-1">Interpretation <a class="header-anchor" href="#interpretation" aria-label="Permalink to &quot;Interpretation&quot;">​</a></h3><p>Capy&#39;s 75.3% score is notable for several reasons:</p><ol><li><p><strong>Cloud IDE vs terminal agents</strong>: Terminal-Bench is designed for terminal-based agents, so Capy (a cloud IDE) may be at a structural disadvantage compared to terminal-native tools like ForgeCode.</p></li><li><p><strong>Single model configuration</strong>: Only one model configuration (Claude Opus 4.6) has a published score. Other agents (Droid, ForgeCode) show results across multiple model configurations.</p></li><li><p><strong>Captain/Build overhead</strong>: The two-agent architecture adds a planning step before execution begins. On benchmark tasks (which tend to be well-specified), this planning phase may add overhead without proportional benefit — the task description is already the spec.</p></li><li><p><strong>Parallel advantage not captured</strong>: Capy&#39;s primary differentiator (parallel task execution) is not measured by Terminal-Bench, which evaluates individual task completion.</p></li></ol><h2 id="other-benchmarks" tabindex="-1">Other Benchmarks <a class="header-anchor" href="#other-benchmarks" aria-label="Permalink to &quot;Other Benchmarks&quot;">​</a></h2><p>No other publicly available benchmark results for Capy were found as of this research. The platform&#39;s strengths (parallel execution, team collaboration, async workflows) are difficult to capture in standard coding benchmarks, which typically measure single-task, single-agent performance.</p><h2 id="what-would-better-measure-capy" tabindex="-1">What Would Better Measure Capy <a class="header-anchor" href="#what-would-better-measure-capy" aria-label="Permalink to &quot;What Would Better Measure Capy&quot;">​</a></h2><p>Benchmarks that would better capture Capy&#39;s strengths:</p><ul><li><strong>Sprint-level benchmarks</strong>: Multiple related tasks executed in parallel, measuring total completion time and consistency</li><li><strong>Spec quality benchmarks</strong>: Evaluating the Captain agent&#39;s ability to produce specs that lead to correct implementations</li><li><strong>Ambiguity resolution benchmarks</strong>: Measuring how well Captain&#39;s clarification questions resolve underspecified tasks</li><li><strong>Team collaboration benchmarks</strong>: Multiple users and agents working on the same repository concurrently</li></ul>',16)])])}const m=t(o,[["render",s]]);export{u as __pageData,m as default};
